3	const chunks: Buffer[] = [];
4	process.stdin.on("data", (c) => chunks.push(c));
5	process.stdin.on("end", () => {
6	  const input = JSON.parse(Buffer.concat(chunks).toString("utf-8"));
7	  const customer = input.customer;
8	  const results = input.steps.map((step: { op: string; items: unknown[] }) => {
9	    if (step.op === "quote") {
10	      return { premium: quote({ items: step.items as never, customer }) };
11	    }
12	    return {};
13	  });
14	  process.stdout.write(JSON.stringify({ results }));
